1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isLive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isLive && neighborCount === 2);
13	
14	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
15	  const liveKeys = new Set(liveCells.map(keyOf));
16	  const neighborCounts = new Map<string, number>();
17	  const candidates = new Map<string, Cell>();
18	
19	  for (const [x, y] of liveCells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const neighbor: Cell = [x + dx, y + dy];
22	      const k = keyOf(neighbor);
23	      candidates.set(k, neighbor);
24	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
25	    }
26	  }
27	
28	  const next: Cell[] = [];
29	  for (const [k, cell] of candidates) {
30	    if (survives(liveKeys.has(k), neighborCounts.get(k) ?? 0)) next.push(cell);
31	  }
32	  return next;
33	};
