5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty grid stays empty — [] → []", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
15	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
16	  });
17	  it("block (still life) stays the same — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
18	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
20	  });
21	  it("live cell with 4 neighbors dies (overpopulation) — center of full 3x3 dies", () => {
22	    const full3x3: Cell[] = [
23	      [0, 0], [1, 0], [2, 0],
24	      [0, 1], [1, 1], [2, 1],
25	      [0, 2], [1, 2], [2, 2],
