export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const candidates = new Map<string, { cell: Cell; neighbors: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = keyOf(cell);
      const entry = candidates.get(key);
      if (entry) entry.neighbors += 1;
      else candidates.set(key, { cell, neighbors: 1 });
    }
  }

  const next: Cell[] = [];
  for (const [key, { cell, neighbors }] of candidates) {
    if (survives(liveKeys.has(key), neighbors)) next.push(cell);
  }
  return next;
};

